/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    let total_sum_x = 0;
    const n = nums.length;

    // The goal is to make nums[i] <= nums[i+1] for all 0 <= i < n-1.
    // If nums[i] > nums[i+1], we need to increase nums[i+1] (and potentially elements after it)
    // or decrease nums[i] (which is not allowed, only increases are allowed on subsegments).
    //
    // Consider the requirement at index i: nums[i] <= nums[i+1].
    // If nums[i] > nums[i+1], the difference d = nums[i] - nums[i+1] must be covered.
    // This difference d must be covered by increases applied to nums[i+1] (and subsequent elements)
    // that are *not* applied to nums[i].
    //
    // Let x_k be the total amount added to the segment starting at index k.
    // For any element nums[j], the final value is nums[j] + total_increase[j].
    //
    // A simpler perspective:
    // We are looking for the minimum sum of x's used across all operations.
    // This problem can be simplified by focusing on the required increases at each step where nums[i] > nums[i+1].
    //
    // If nums[i] > nums[i+1], we need nums[i+1] to effectively increase by at least (nums[i] - nums[i+1]).
    // The most efficient way to satisfy this specific local constraint (nums[i] <= nums[i+1]) while
    // minimizing the total sum of x's is to apply an operation with x = nums[i] - nums[i+1]
    // to the subarray starting at i+1 (and extending as far as needed).
    //
    // Let's track the required "boost" at each position relative to the previous one.
    //
    // If nums[i] <= nums[i+1], no immediate positive change is needed at i+1 relative to i.
    // If nums[i] > nums[i+1], we need nums[i+1] to increase by at least `d = nums[i] - nums[i+1]`.
    // This increase `d` must come from some operation covering index i+1.
    // Since we want to minimize the sum of x's, we should apply this increase `d` once,
    // specifically targeting index i+1 and beyond.
    //
    // The crucial insight from similar problems (e.g., making an array non-decreasing by adding to suffixes)
    // is that the total sum of x's required is the sum of all positive differences `nums[i] - nums[i+1]`.
    //
    // Example 1: [3, 3, 2, 1]
    // i=0: 3 <= 3. Diff = 0.
    // i=1: 3 > 2. Need increase of 1 at index 2 relative to index 1. Add 1 to total_sum_x. Total = 1.
    // i=2: 2 > 1. Need increase of 1 at index 3 relative to index 2. Add 1 to total_sum_x. Total = 2.
    // Result: 2. Matches example.
    //
    // Example 2: [5, 1, 2, 3]
    // i=0: 5 > 1. Need increase of 4 at index 1 relative to index 0. Add 4 to total_sum_x. Total = 4.
    // i=1: 1 <= 2. Diff = 0.
    // i=2: 2 <= 3. Diff = 0.
    // Result: 4. Matches example.
    //
    // This greedy strategy works because an operation of size x on [l..r] contributes x to the relative difference
    // only at index l-1 vs l (if l>0) and potentially helps satisfy the constraint at r vs r+1.
    // By only summing up the required deficits (nums[i] - nums[i+1] > 0), we are essentially calculating
    // the minimum required "lift" needed at each step i+1 to overcome the previous element nums[i].

    for (let i = 0; i < n - 1; i++) {
        if (nums[i] > nums[i + 1]) {
            // The required increase at index i+1 to match nums[i] is nums[i] - nums[i+1].
            const required_increase = nums[i] - nums[i + 1];
            total_sum_x += required_increase;
        }
    }

    return total_sum_x;
}

